// Map service tile IDs to group names in SERVICES_DATA
export const SERVICE_ID_TO_GROUP: Record<string, string> = {
  "record-room": "Record Room Documents",
  "survey": "Survey Documents",
};

// Get main services for a group
export function getMainServices(groupName: string): string[] {
  const group = SERVICES_DATA[groupName];
  return group ? Object.keys(group).sort() : [];
}

// Get sub services for a main service within a group
export function getSubServices(groupName: string, mainService: string): string[] {
  const group = SERVICES_DATA[groupName];
  if (!group || !group[mainService]) return [];
  return Object.keys(group[mainService]).sort();
}

// Get required documents for a specific sub service
export function getRequiredDocuments(groupName: string, mainService: string, subService: string): string[] {
  const group = SERVICES_DATA[groupName];
  if (!group || !group[mainService] || !group[mainService][subService]) return [];
  return group[mainService][subService];
}

